import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Component;

import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Component
public class GetPostCommentsUseCase {

    private final PostRepository postRepository;
    private final PostCommentRepository postCommentRepository;

    public GetPostCommentsUseCase(PostRepository postRepository, PostCommentRepository postCommentRepository) {
        this.postRepository = postRepository;
        this.postCommentRepository = postCommentRepository;
    }

    public Page<PostCommentTreeResponse> execute(String postId, Pageable pageable) {
        postRepository.findById(postId)
                .orElseThrow(() -> new IllegalArgumentException("Post não encontrado"));

        Page<PostComment> rootPage = postCommentRepository.findRootCommentsByPostId(postId, pageable);

        if (rootPage.isEmpty()) {
            return Page.empty(pageable);
        }

        List<String> rootIds = rootPage.getContent().stream()
                .map(PostComment::getId)
                .toList();

        Map<String, List<PostComment>> childrenByParentId = postCommentRepository
                .findRepliesByPostIdAndParentIds(postId, rootIds)
                .stream()
                .collect(Collectors.groupingBy(PostComment::getResponseTo));

        return rootPage.map(root -> buildTree(root, childrenByParentId));
    }

    private PostCommentTreeResponse buildTree(PostComment comment,
                                              Map<String, List<PostComment>> childrenByParentId) {
        List<PostCommentTreeResponse> replies = childrenByParentId
                .getOrDefault(comment.getId(), List.of())
                .stream()
                .map(child -> buildTree(child, childrenByParentId))
                .toList();
        return PostCommentTreeResponse.from(comment, replies);
    }
}

package com.projectC.api.infrastructure.api.post.controller;

import com.projectC.api.application.post.GetFollowing24hFeedUseCase;
import com.projectC.api.application.post.GetFollowingFeedUseCase;
import com.projectC.api.domain.model.User;
import com.projectC.api.infrastructure.api.common.PageResponse;
import com.projectC.api.infrastructure.api.post.model.response.FeedPostResponse;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.data.web.PageableDefault;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/feed")
public class FeedController implements FeedAPI {

    private final GetFollowingFeedUseCase getFollowingFeedUseCase;
    private final GetFollowing24hFeedUseCase getFollowing24hFeedUseCase;

    public FeedController(GetFollowingFeedUseCase getFollowingFeedUseCase,
                          GetFollowing24hFeedUseCase getFollowing24hFeedUseCase) {
        this.getFollowingFeedUseCase = getFollowingFeedUseCase;
        this.getFollowing24hFeedUseCase = getFollowing24hFeedUseCase;
    }

    /**
     * GET /feed/following?page=0&size=20
     * Retorna posts paginados de quem o usuário segue, ordenados do mais recente para o mais antigo.
     */
    @GetMapping("/following")
    @Override
    public ResponseEntity<PageResponse<FeedPostResponse>> getFollowingFeed(
            @AuthenticationPrincipal User user,
            @PageableDefault(size = 20, sort = "createdAt", direction = Sort.Direction.DESC) Pageable pageable) {
        return ResponseEntity.ok(
                PageResponse.from(getFollowingFeedUseCase.execute(user, pageable).map(FeedPostResponse::from))
        );
    }

    /**
     * GET /feed/following/24h?page=0&size=20
     * Retorna posts criados nas últimas 24h de quem o usuário segue.
     */
    @GetMapping("/following/24h")
    @Override
    public ResponseEntity<PageResponse<FeedPostResponse>> getFollowing24hFeed(
            @AuthenticationPrincipal User user,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int size) {
        return ResponseEntity.ok(
                PageResponse.from(getFollowing24hFeedUseCase.execute(user, page, size).map(FeedPostResponse::from))
        );
    }
}

